import React, { useRef, useState, useEffect, memo } from 'react';
import { Col } from 'react-bootstrap';

/**
 * Animated counter component for statistics.
 * Uses IntersectionObserver to trigger counting when visible.
 */
const StatsItem = ({ icon: Icon, target, label, suffix = "", duration = 2000 }) => {
    const [count, setCount] = useState(0);
    const [hasStarted, setHasStarted] = useState(false);
    const elementRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting && !hasStarted) {
                    setHasStarted(true);
                }
            },
            { threshold: 0.1 }
        );

        if (elementRef.current) observer.observe(elementRef.current);
        return () => observer.disconnect();
    }, [hasStarted]);

    useEffect(() => {
        if (!hasStarted) return;

        const totalFrames = Math.round(duration / 16); // ~60fps
        const increment = target / totalFrames;

        let frame = 0;
        const timer = setInterval(() => {
            frame++;
            const nextValue = Math.min(Math.round(increment * frame), target);
            setCount(nextValue);

            if (nextValue >= target) clearInterval(timer);
        }, 16);

        return () => clearInterval(timer);
    }, [hasStarted, target, duration]);

    return (
        <Col lg={3} md={6} className="mb-4 mb-lg-0" ref={elementRef}>
            <div className="stat-card glass-card p-4 rounded-4 text-center h-100 hover-glow">
                <div className="stat-icon-wrapper mb-3 mx-auto shadow-sm">
                    <Icon size={24} />
                </div>
                <h2 className="display-5 fw-bold text-dark mb-1">
                    {count.toLocaleString()}{suffix}
                </h2>
                <p className="text-muted small fw-bold text-uppercase tracking-widest">{label}</p>
            </div>
        </Col>
    );
};

export default memo(StatsItem);

import React, { useEffect, useState, useMemo, useCallback } from 'react';
import { Container, Row, Col, Form, Button, Badge } from 'react-bootstrap';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { FaChevronRight, FaSearch, FaArrowRight, FaSyncAlt } from 'react-icons/fa';
import { Zap, Star, Filter } from 'lucide-react';

// Data & Hooks
import { categories, allTools } from '../../data/toolsData';
import useToolSearch from '../../hooks/useToolSearch';
import SEO from '../../components/SEO';

// Styles
import "./Tools.css";

/**
 * Tools Component
 * Catalog page displaying all available tools with filtering and search capabilities.
 */
const Tools = () => {
    const location = useLocation();
    const queryParams = new URLSearchParams(location.search);

    // Phase 3: Centralized Search Logic
    const { 
        searchQuery, 
        setSearchQuery, 
        handleSearchSubmit 
    } = useToolSearch(queryParams.get('q') || '');

    const navigate = useNavigate();
    const activeCategory = queryParams.get('category') || 'all';
    const [visibleCount, setVisibleCount] = useState(12);
    const [isLoading, setIsLoading] = useState(false);

    // Sync search query from URL
    useEffect(() => {
        const q = queryParams.get('q') || '';
        if (q !== searchQuery) {
            setSearchQuery(q);
        }
    }, [location.search, searchQuery, setSearchQuery]);

    // Handle Pagination
    const handleLoadMore = useCallback(() => {
        setIsLoading(true);
        setTimeout(() => {
            setVisibleCount(prev => prev + 12);
            setIsLoading(false);
        }, 600);
    }, []);

    // Filter Logic
    const filteredTools = useMemo(() => {
        return allTools.filter(tool => {
            const matchesSearch = tool.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                                tool.desc.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesCat = activeCategory === 'all' || tool.category === activeCategory;
            return matchesSearch && matchesCat;
        });
    }, [searchQuery, activeCategory]);

    const displayedTools = useMemo(() => filteredTools.slice(0, visibleCount), [filteredTools, visibleCount]);

    const clearFilters = useCallback(() => {
        navigate('/tools');
    }, [navigate]);

    const handleCategoryClick = (catId) => {
        const q = queryParams.get('q');
        const search = q ? `?category=${catId}&q=${q}` : `?category=${catId}`;
        navigate(`/tools${search}`);
    };

    return (
        <div className="tools-catalog-wrapper">
            <SEO
                title="Tools Catalog | WebzenTools"
                description="Browse our massive collection of premium developer, writing, and finance tools."
                keywords="online tools, json formatter, emi calculator, ai text generator, developer tools"
                url="https://webzentools.com/tools"
            />

            {/* HERO SECTION */}
            <section className="tools-hero text-center py-5 position-relative overflow-hidden bg-dark text-white">
                <div className="hero-glow"></div>
                <Container className="position-relative z-2 py-5">
                    <div className="wt-glass-breadcrumb d-inline-flex align-items-center mb-4">
                        <Link to="/" className="text-white-50 text-decoration-none">Home</Link>
                        <FaChevronRight size={10} className="mx-3 opacity-50" />
                        <span className="fw-bold">Tools</span>
                    </div>
                    <h1 className="display-4 fw-bold mb-3">All <span className="text-gradient">Premium Tools</span></h1>
                    <p className="lead text-white-50 mx-auto pb-4" style={{ maxWidth: '700px' }}>
                        Empower your workflow with our production-grade utility suite. 
                        Zero costs, maximum performance.
                    </p>

                    {/* TOP SEARCH BAR */}
                    <div className="mx-auto" style={{ maxWidth: '600px' }}>
                        <Form onSubmit={handleSearchSubmit}>
                            <div className="glass-card p-2 rounded-pill d-flex align-items-center shadow-lg bg-white bg-opacity-10">
                                <div className="px-3 text-primary"><FaSearch /></div>
                                <Form.Control 
                                    type="text" 
                                    placeholder="Search among 100+ tools..." 
                                    className="border-0 bg-transparent shadow-none text-white placeholder-white"
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                />
                            </div>
                        </Form>
                    </div>
                </Container>
            </section>

            {/* TOOLS EXPLORER */}
            <section className="py-5 bg-light">
                <Container>
                    <Row className="g-4">
                        {/* FILTER SIDEBAR (Desktop) */}
                        <Col lg={3}>
                            <div className="filter-sidebar sticky-top" style={{ top: '100px' }}>
                                <div className="d-flex align-items-center mb-4">
                                    <Filter size={20} className="text-primary me-2" />
                                    <h5 className="fw-bold mb-0 text-dark">Categories</h5>
                                </div>
                                <div className="category-list d-flex flex-column gap-1">
                                    <button 
                                        className={`category-filter-btn ${activeCategory === 'all' ? 'active' : ''}`}
                                        onClick={() => handleCategoryClick('all')}
                                    >
                                        All Tools <span className="ms-auto badge rounded-pill bg-primary">{allTools.length}</span>
                                    </button>
                                    {categories.map(cat => {
                                        const Icon = cat.icon;
                                        return (
                                            <button 
                                                key={cat.id}
                                                className={`category-filter-btn ${activeCategory === cat.id ? 'active' : ''}`}
                                                onClick={() => handleCategoryClick(cat.id)}
                                            >
                                                <span className={cat.color + ' me-2'}><Icon size={18} /></span>
                                                {cat.name}
                                                <span className="ms-auto badge rounded-pill bg-light text-dark border">{cat.count}</span>
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </Col>

                        {/* TOOLS GRID */}
                        <Col lg={9}>
                            <div className="d-flex justify-content-between align-items-center mb-4">
                                <h6 className="text-muted mb-0">Found <strong>{filteredTools.length}</strong> tools</h6>
                            </div>

                            <Row className="g-4">
                                {displayedTools.length > 0 ? (
                                    displayedTools.map((tool) => (
                                        <Col md={6} xl={4} key={tool.id}>
                                            <Link to={`/tools/${tool.slug}`} className="text-decoration-none h-100 d-block">
                                                <div className="tool-card-premium glass-card p-4 rounded-4 h-100 d-flex flex-column hover-glow transition-all bg-white">
                                                    <div className="d-flex justify-content-between mb-4">
                                                        <div className="tool-icon-sm p-2 bg-primary bg-opacity-10 rounded-3 text-primary">
                                                            <Zap size={20} />
                                                        </div>
                                                        {tool.isPremium && <Badge bg="warning" className="rounded-pill"><Star size={10} /> PRO</Badge>}
                                                    </div>
                                                    <h5 className="fw-bold text-dark mb-2">{tool.name}</h5>
                                                    <p className="text-muted small mb-4 flex-grow-1">{tool.desc}</p>
                                                    <div className="mt-auto pt-3 border-top border-secondary border-opacity-10 d-flex align-items-center justify-content-between">
                                                        <span className="small text-uppercase tracking-wider fw-bold text-muted" style={{ fontSize: '0.65rem' }}>{tool.category}</span>
                                                        <FaArrowRight className="text-primary tool-arrow-icon" />
                                                    </div>
                                                </div>
                                            </Link>
                                        </Col>
                                    ))
                                ) : (
                                    <Col xs={12}>
                                        <div className="text-center py-5 glass-card rounded-4 bg-white">
                                            <h3 className="fw-bold text-dark">No results found</h3>
                                            <p className="text-muted">Try adjusting your filters or search query.</p>
                                            <Button variant="primary" onClick={clearFilters}>Clear All Filters</Button>
                                        </div>
                                    </Col>
                                )}
                            </Row>

                            {/* LOAD MORE */}
                            {filteredTools.length > visibleCount && (
                                <div className="text-center mt-5">
                                    <button 
                                        className="btn btn-primary rounded-pill px-5 py-3 fw-bold shadow-lg"
                                        onClick={handleLoadMore}
                                        disabled={isLoading}
                                    >
                                        {isLoading ? <><FaSyncAlt className="fa-spin me-2" /> Loading...</> : 'Load More Tools'}
                                    </button>
                                </div>
                            )}
                        </Col>
                    </Row>
                </Container>
            </section>
        </div>
    );
};

export default Tools;

import React, { useState, useEffect, useCallback } from "react";
import { toast } from "react-hot-toast";
import { 
  FaEdit, FaCopy, FaDownload, FaExclamationTriangle, 
  FaCheck, FaTrash, FaUndo, FaFileImport, 
  FaExchangeAlt, FaLink, FaKeyboard 
} from "react-icons/fa";
import "./Base64EncodeDecode.css";

const Base64EncodeDecode = () => {
  const [input, setInput] = useState("");
  const [output, setOutput] = useState("");
  const [mode, setMode] = useState("encode"); // 'encode' or 'decode'
  const [urlSafe, setUrlSafe] = useState(false);
  const [autoUpdate, setAutoUpdate] = useState(true);
  const [error, setError] = useState("");
  const [fileName, setFileName] = useState("");

  const encodeBase64 = useCallback((str, safe) => {
    try {
      // UTF-8 friendly encoding
      const bytes = new TextEncoder().encode(str);
      const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
      let base64 = btoa(binString);

      if (safe) {
        base64 = base64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
      }
      return base64;
    } catch (err) {
      throw new Error("Failed to encode: " + err.message);
    }
  }, []);

  const decodeBase64 = useCallback((str, safe) => {
    try {
      let base64 = str;
      if (safe) {
        base64 = base64.replace(/-/g, "+").replace(/_/g, "/");
        while (base64.length % 4) base64 += "=";
      }

      const binString = atob(base64);
      const bytes = Uint8Array.from(binString, (m) => m.charCodeAt(0));
      return new TextDecoder().decode(bytes);
    } catch (err) {
      throw new Error("Invalid Base64 string");
    }
  }, []);

  const process = useCallback(() => {
    if (!input.trim()) {
      setOutput("");
      setError("");
      return;
    }

    try {
      setError("");
      if (mode === "encode") {
        setOutput(encodeBase64(input, urlSafe));
      } else {
        setOutput(decodeBase64(input, urlSafe));
      }
    } catch (e) {
      setError(e.message);
      setOutput("");
    }
  }, [input, mode, urlSafe, encodeBase64, decodeBase64]);

  useEffect(() => {
    if (autoUpdate) {
      const timer = setTimeout(process, 300);
      return () => clearTimeout(timer);
    }
  }, [input, mode, urlSafe, autoUpdate, process]);

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setFileName(file.name);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target.result;
      const stripped = base64.split(",")[1] || base64;
      setInput(stripped);
      setMode("decode"); // Usually when you upload a file as base64, you want to decode it or see it. 
      // But wait, if they upload a BINARY file, they want to ENCODE it.
      setInput(base64); // Full data URI
      setMode("decode");
      toast.success("File loaded successfully!");
    };
    reader.readAsDataURL(file);
  };

  const handleAction = () => {
    process();
    if (!error && input.trim()) {
      toast.success(`${mode === "encode" ? "Encoded" : "Decoded"} successfully!`);
    } else if (error) {
      toast.error(error);
    }
  };

  const swap = () => {
    if (output) {
      setInput(output);
      setMode(mode === "encode" ? "decode" : "encode");
      setOutput("");
    }
  };

  const clearAll = () => {
    setInput("");
    setOutput("");
    setError("");
    setFileName("");
    toast.success("Cleared everything!");
  };

  const handleCopy = () => {
    if (!output) return;
    navigator.clipboard.writeText(output).then(() => {
      toast.success("Copied to clipboard!");
    });
  };

  const handleDownload = () => {
    if (!output) return;
    const blob = new Blob([output], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `base64_${mode}_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    toast.success("Result downloaded!");
  };

  const loadSample = () => {
    if (mode === "encode") {
      setInput("WebZenTools - The Ultimate All-in-One Developer Platform! 🚀");
    } else {
      setInput("V2ViWmVuVG9vbHMgLSBUaGUgVWx0aW1hdGUgQWxsLWluLU9uZSBEZXZlbG9wZXIgUGxhdGZvcm0hIA==");
    }
    toast.success("Sample data loaded.");
  };

  return (
    <div className="base64-tool-bg">


      <div className="container tool-content">

        <div className="row g-4 justify-content-center">
          {/* CONTROL PANEL */}
          <div className="col-12">
            <div className="premium-card p-3 mb-4 control-strip">
              <div className="d-flex flex-wrap align-items-center justify-content-between gap-3">
                <div className="btn-group premium-toggle" role="group">
                  <button 
                    className={`btn ${mode === "encode" ? "btn-primary" : "btn-outline-secondary"}`}
                    onClick={() => setMode("encode")}
                  >
                    <FaEdit className="me-2" /> Encode
                  </button>
                  <button 
                    className={`btn ${mode === "decode" ? "btn-primary" : "btn-outline-secondary"}`}
                    onClick={() => setMode("decode")}
                  >
                    <FaCheck className="me-2" /> Decode
                  </button>
                </div>

                <div className="d-flex align-items-center gap-3">
                  <div className="form-check form-switch premium-switch">
                    <input 
                      className="form-check-input" 
                      type="checkbox" 
                      id="urlSafeSwitch" 
                      checked={urlSafe}
                      onChange={(e) => setUrlSafe(e.target.checked)}
                    />
                    <label className="form-check-label" htmlFor="urlSafeSwitch">
                      <FaLink className="me-1 opacity-75" /> URL Safe
                    </label>
                  </div>
                  <div className="form-check form-switch premium-switch">
                    <input 
                      className="form-check-input" 
                      type="checkbox" 
                      id="autoUpdateSwitch" 
                      checked={autoUpdate}
                      onChange={(e) => setAutoUpdate(e.target.checked)}
                    />
                    <label className="form-check-label" htmlFor="autoUpdateSwitch">Auto-Update</label>
                  </div>
                </div>

                <div className="d-flex gap-2">
                  <button className="btn btn-action" onClick={loadSample} title="Load Sample Data">
                    <FaKeyboard /> <span className="d-none d-md-inline ms-1">Sample</span>
                  </button>
                  <button className="btn btn-action text-danger" onClick={clearAll} title="Clear All">
                    <FaTrash /> <span className="d-none d-md-inline ms-1">Clear</span>
                  </button>
                </div>
              </div>
            </div>
          </div>

          {/* INPUT SECTION */}
          <div className="col-lg-6">
            <div className="premium-card h-100 p-4">
              <div className="d-flex justify-content-between align-items-center mb-3">
                <h5 className="fw-bold m-0 d-flex align-items-center">
                  Input {mode === "encode" ? "Text" : "Base64"}
                </h5>
                <div className="file-input-wrapper">
                  <label className="btn btn-sm btn-outline-primary m-0">
                    <FaFileImport className="me-1" /> {fileName ? "Change" : "Upload File"}
                    <input type="file" onChange={handleFileChange} hidden />
                  </label>
                </div>
              </div>
              {fileName && <div className="file-name-badge mb-2">📁 {fileName}</div>}
              <textarea
                className={`form-control premium-input ${error ? 'border-danger' : ''}`}
                rows={12}
                placeholder={mode === "encode" ? "Enter text here..." : "Enter Base64 string here..."}
                value={input}
                onChange={(e) => setInput(e.target.value)}
              />
              {error && (
                <div className="error-msg mt-2 d-flex align-items-center text-danger">
                  <FaExclamationTriangle className="me-2" /> {error}
                </div>
              )}
              <div className="mt-3 d-flex gap-2">
                {!autoUpdate && (
                  <button className="btn btn-primary w-100" onClick={handleAction}>
                    {mode === "encode" ? "Encode Now" : "Decode Now"}
                  </button>
                )}
              </div>
            </div>
          </div>

          {/* SWAP ICON (Desktop Only) */}
          <div className="col-12 d-lg-none text-center">
             <button className="btn btn-swap-mobile" onClick={swap}>
                <FaExchangeAlt />
             </button>
          </div>

          {/* OUTPUT SECTION */}
          <div className="col-lg-6">
            <div className="premium-card h-100 p-4 output-card">
              <div className="d-flex justify-content-between align-items-center mb-3">
                <h5 className="fw-bold m-0">Result</h5>
                <div className="d-flex gap-2">
                  <button 
                    className="btn btn-sm btn-action" 
                    onClick={handleCopy} 
                    disabled={!output}
                    title="Copy Result"
                  >
                    <FaCopy />
                  </button>
                  <button 
                    className="btn btn-sm btn-action" 
                    onClick={handleDownload} 
                    disabled={!output}
                    title="Download Result"
                  >
                    <FaDownload />
                  </button>
                  <button 
                    className="btn btn-sm btn-action" 
                    onClick={swap} 
                    disabled={!output}
                    title="Swap Input/Output"
                  >
                    <FaExchangeAlt />
                  </button>
                </div>
              </div>
              <div className="result-container">
                <pre className="premium-output">
                  {output || "Output will appear here..."}
                </pre>
              </div>
            </div>
          </div>
        </div>

        {/* ABOUT TOOL */}
        <section className="about-tool mt-5 pt-4">
          <div className="premium-card p-5">
            <h2 className="section-title">What is Base64?</h2>
            <div className="row mt-4">
              <div className="col-md-8">
                <p className="text-muted leading-relaxed">
                  Base64 is a binary-to-text encoding scheme that represents binary data in an ASCII string format. 
                  It is commonly used to embed image data in HTML/CSS or to transmit binary data over systems that 
                  only handle text properly.
                </p>
                <div className="feature-list mt-4">
                  <div className="feature-item">
                    <FaCheck className="text-success me-2" />
                    <span><strong>Security:</strong> All processing happens in your browser. No data is sent to our servers.</span>
                  </div>
                  <div className="feature-item mt-2">
                    <FaCheck className="text-success me-2" />
                    <span><strong>UTF-8 Support:</strong> Handles emojis and special characters correctly across all languages.</span>
                  </div>
                  <div className="feature-item mt-2">
                    <FaCheck className="text-success me-2" />
                    <span><strong>URL Safe:</strong> Converts +, / to -, _ respectively for safe usage in URL components.</span>
                  </div>
                </div>
              </div>
              <div className="col-md-4 d-none d-md-flex align-items-center justify-content-center">
                <div className="info-icon-box">
                  <FaEdit size={40} className="text-primary mb-3" />
                  <span className="small text-muted text-center d-block">Developer Tool</span>
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>
    </div>
  );
};

export default Base64EncodeDecode;

import React, { useState, useEffect, useRef } from 'react';
import { Container, Row, Col, Button, Badge, Spinner, Nav } from 'react-bootstrap';
import { 
    FaCoffee, FaPlay, FaTrash, FaCopy, FaDownload, 
    FaTerminal, FaCode, FaCheckCircle, FaFileCode, FaMagic,
    FaBoxOpen, FaLayerGroup, FaBolt
} from 'react-icons/fa';
import SEO from '../../../../components/SEO';
import "./JavaEditor.css";

const javaTemplates = {
    hello: `public class Main {
    public static void main(String[] args) {
        System.out.println("Hello, Webzen Java Studio!");
        System.out.println("Running Java in the browser is amazing!");
    }
}`,
    oop: `public class User {
    private String name;
    private int id;

    public User(String name, int id) {
        this.name = name;
        this.id = id;
    }

    public void display() {
        System.out.println("User: " + name + " (ID: " + id + ")");
    }

    public static void main(String[] args) {
        User admin = new User("Webzen Dev", 1);
        admin.display();
    }
}`,
    streams: `import java.util.Arrays;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        List<String> tools = Arrays.asList("HTML", "CSS", "JS", "Java");

        tools.stream()
             .filter(t -> t.startsWith("J"))
             .map(String::toUpperCase)
             .forEach(System.out::println);
    }
}`
};

const JavaEditor = () => {
    const [code, setCode] = useState(javaTemplates.hello);
    const [logs, setLogs] = useState([]);
    const [isCompiling, setIsCompiling] = useState(false);
    const [copySuccess, setCopySuccess] = useState('');
    const [activeTab, setActiveTab] = useState('hello');
    const consoleEndRef = useRef(null);

    useEffect(() => {
        consoleEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [logs]);

    const compileAndRun = () => {
        setIsCompiling(true);
        setLogs([{ type: 'info', content: 'javac Main.java...', time: new Date().toLocaleTimeString() }]);

        setTimeout(() => {
            const output = [];
            // Basic pattern matching to simulate System.out.println output
            const lines = code.split('\n');
            lines.forEach(line => {
                const match = line.match(/System\.out\.println\((.*)\)/);
                if (match) {
                    let val = match[1].trim();
                    // Basic cleanup for the mock console
                    if (val.startsWith('"') && val.endsWith('"')) {
                        val = val.substring(1, val.length - 1);
                    }
                    output.push(val);
                }
            });

            if (output.length === 0) {
                setLogs(prev => [...prev, 
                    { type: 'warning', content: 'Compilation successful. No output generated.', time: new Date().toLocaleTimeString() },
                    { type: 'info', content: '(Tip: Use System.out.println to see results here)', time: new Date().toLocaleTimeString() }
                ]);
            } else {
                setLogs(prev => [
                    ...prev,
                    { type: 'success', content: 'Compilation successful. Starting JVM...', time: new Date().toLocaleTimeString() },
                    ...output.map(o => ({ type: 'log', content: o, time: new Date().toLocaleTimeString() })),
                    { type: 'info', content: 'Process finished with exit code 0', time: new Date().toLocaleTimeString() }
                ]);
            }
            setIsCompiling(false);
        }, 1200);
    };

    const handleCopy = () => {
        navigator.clipboard.writeText(code);
        setCopySuccess('Java Copied!');
        setTimeout(() => setCopySuccess(''), 2000);
    };

    const handleDownload = () => {
