            env: { NODE_ENV: 'production' }
        };

        const module = { exports: {} };

        // Override console.log
        const originalLog = console.log;
        console.log = (...args) => {
            const output = args.map(arg => typeof arg === 'object' ? JSON.stringify(arg, null, 2) : String(arg)).join(' ');
