    // 🔥 IMAGE ENHANCEMENT FUNCTION
    const enhanceImage = () => {
        if (!imageURL) return toast.error("Upload image first");

        setLoading(true);

        const img = new Image();
        img.src = imageURL;

        img.onload = () => {
            const canvas = canvasRef.current;
            const ctx = canvas.getContext("2d");

            // 🔥 Keep size almost same (no huge resize)
            const width = img.width;
            const height = img.height;

            canvas.width = width;
            canvas.height = height;

            ctx.drawImage(img, 0, 0, width, height);

            // 🔥 Apply Filters based on mode
            let imageData = ctx.getImageData(0, 0, width, height);
            let data = imageData.data;

            // Enhancement strength
            let sharpness = 0;
            let contrast = 1;
            let brightness = 0;

            if (mode === "2x") {
                sharpness = 0.2;
                contrast = 1.1;
            } else if (mode === "4k") {
                sharpness = 0.4;
                contrast = 1.2;
                brightness = 5;
            } else if (mode === "8k") {
                sharpness = 0.6;
                contrast = 1.3;
                brightness = 10;
            }

            // 🔥 Apply Enhancement Loop
            for (let i = 0; i < data.length; i += 4) {
                // contrast + brightness
                data[i] = data[i] * contrast + brightness;     // R
                data[i + 1] = data[i + 1] * contrast + brightness; // G
                data[i + 2] = data[i + 2] * contrast + brightness; // B

                // clamp
                data[i] = Math.min(255, Math.max(0, data[i]));
                data[i + 1] = Math.min(255, Math.max(0, data[i + 1]));
                data[i + 2] = Math.min(255, Math.max(0, data[i + 2]));
            }

            ctx.putImageData(imageData, 0, 0);

            // 🔥 EXTRA SHARPEN (canvas filter trick)
            ctx.filter = `contrast(${contrast}) brightness(${100 + brightness}%)`;
            ctx.drawImage(canvas, 0, 0);

            ctx.filter = "none";

            setLoading(false);
        };
