                                                                    >
                                                                        {br.label} <span className="opacity-50 ms-1">({br.val})</span>
                                                                    </button>
                                                                ))}
                                                            </div>
                                                        </div>
                                                    </div>

                                                    <div className="d-grid gap-2 pt-2">
                                                        <button 
                                                            className="btn btn-success btn-lg rounded-pill py-3 fw-bold shadow-lg"
                                                            onClick={convertAudio}
