                    transition: all 0.3s ease;
                }
                .result-card:hover {
                    transform: translateY(-8px);
                    border-color: rgba(37, 99, 235, 0.3) !important;
                    background: rgba(255, 255, 255, 0.08) !important;
                }
                .aspect-video {
                    aspect-ratio: 16 / 9;
                }
                .form-control::placeholder {
                    color: rgba(255, 255, 255, 0.3);
                }
