            // -vn: disable video
            // -ab: audio bitrate
            // -ar: audio rate
            await ffmpeg.exec([
                '-i', inputName,
                '-vn',
                '-acodec', 'libmp3lame',
                '-ab', '192k',
                '-ar', '44100',
                outputName
            ]);

            const data = await ffmpeg.readFile(outputName);
            const blob = new Blob([data.buffer], { type: 'audio/mpeg' });
            const url = URL.createObjectURL(blob);

            setMp3Url(url);
            setStatus('finished');
            toast.success('Conversion completed successfully!');
