                    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05);
                    margin-bottom: 2rem;
                }
                .upload-zone {
                    border: 2px dashed #cbd5e0;
                    border-radius: 16px;
                    padding: 3rem 2rem;
                    text-align: center;
                    transition: all 0.3s ease;
                    background: #f8fafc;
                    cursor: pointer;
                    margin-bottom: 2rem;
                    position: relative;
                }
                .upload-zone:hover {
                    border-color: #3182ce;
                    background: #ebf8ff;
                }
                .upload-zone input {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    opacity: 0;
                    cursor: pointer;
                }
                .file-list-card {
                    background: #ffffff;
                    border: 1px solid #edf2f7;
                    border-radius: 20px;
                    overflow: hidden;
                    margin-bottom: 2rem;
                }
                .premium-table th {
                    background: #f7fafc;
                    color: #4a5568;
                    font-weight: 700;
                    text-transform: uppercase;
                    font-size: 0.75rem;
                    letter-spacing: 0.05em;
                    padding: 1rem;
                    border: none;
                }
                .premium-table td {
                    padding: 1rem;
                    vertical-align: middle;
                    border-bottom: 1px solid #f7fafc;
                }
                .file-icon {
                    color: #e53e3e;
                    font-size: 1.5rem;
                }
                .action-btn {
                    width: 32px;
                    height: 32px;
                    padding: 0;
                    display: inline-flex;
                    align-items: center;
                    justify-content: center;
                    border-radius: 8px;
                    margin: 0 4px;
                    transition: all 0.2s;
                }
                .btn-merge {
                    background: linear-gradient(135deg, #3182ce 0%, #2c5282 100%);
                    border: none;
                    padding: 1rem 2.5rem;
                    font-weight: 700;
                    border-radius: 12px;
                    box-shadow: 0 4px 15px rgba(49, 130, 206, 0.3);
                    transition: all 0.3s;
