                    border: none;
                    padding: 1rem 2.5rem;
                    font-weight: 700;
                    border-radius: 12px;
                    box-shadow: 0 4px 15px rgba(72, 187, 120, 0.3);
                    transition: all 0.3s;
                }
                .btn-download:hover {
                    transform: translateY(-2px);
