import React, { useState, useRef } from 'react';
import { PDFDocument } from 'pdf-lib';
import * as pdfjsLib from 'pdfjs-dist';
import { Form, Button, Spinner, Row, Col } from 'react-bootstrap';
import { 
    FaFilePdf, FaExchangeAlt, FaDownload, FaFileUpload, 
    FaCheckCircle, FaArrowLeft, FaArrowRight, FaSync 
} from 'react-icons/fa';
import toast from 'react-hot-toast';

// Set up PDF.js worker
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

const PDFPageReorder = () => {
    const [file, setFile] = useState(null);
    const [pages, setPages] = useState([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [resultPdfUrl, setResultPdfUrl] = useState(null);

    const onFileChange = async (e) => {
        const selectedFile = e.target.files[0];
        if (!selectedFile) return;

        if (selectedFile.type !== 'application/pdf') {
            toast.error('Only PDF files are allowed.');
            return;
        }

        setFile(selectedFile);
        setPages([]);
        setResultPdfUrl(null);
        setIsLoading(true);

        try {
            const arrayBuffer = await selectedFile.arrayBuffer();
            const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;

            const loadedPages = [];
            for (let i = 1; i <= pdf.numPages; i++) {
                const page = await pdf.getPage(i);
                const viewport = page.getViewport({ scale: 0.3 });
                const canvas = document.createElement('canvas');
                const context = canvas.getContext('2d');
                canvas.height = viewport.height;
                canvas.width = viewport.width;

                await page.render({ canvasContext: context, viewport }).promise;
                loadedPages.push({
                    id: Math.random().toString(36).substr(2, 9),
                    originalIndex: i - 1,
                    pageNumber: i,
                    thumbnail: canvas.toDataURL()
                });
            }
            setPages(loadedPages);
            toast.success(`PDF Loaded: ${pdf.numPages} pages ready to reorder.`);
        } catch (error) {
            console.error('Error loading PDF:', error);
            toast.error('Failed to read PDF file.');
        } finally {
            setIsLoading(false);
        }
    };

    const movePage = (index, direction) => {
        const newPages = [...pages];
        const newIndex = index + direction;
        if (newIndex < 0 || newIndex >= newPages.length) return;

        [newPages[index], newPages[newIndex]] = [newPages[newIndex], newPages[index]];
        setPages(newPages);
        setResultPdfUrl(null);
    };

    const saveNewOrder = async () => {
        if (!file || pages.length === 0) return;

        setIsProcessing(true);
        try {
            const arrayBuffer = await file.arrayBuffer();
            const sourceDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true });
            const newDoc = await PDFDocument.create();

            // Reconstruct PDF in the new order
            const pageIndices = pages.map(p => p.originalIndex);
            const copiedPages = await newDoc.copyPages(sourceDoc, pageIndices);

            copiedPages.forEach(page => {
                newDoc.addPage(page);
            });

            const pdfBytes = await newDoc.save();
            const blob = new Blob([pdfBytes], { type: 'application/pdf' });
            const url = URL.createObjectURL(blob);

            setResultPdfUrl(url);
            toast.success('New page order saved successfully!');
        } catch (error) {
            console.error('Reorder Error:', error);
            toast.error('An error occurred while reordering pages.');
        } finally {
            setIsProcessing(false);
        }
    };

    const downloadPdf = () => {
        if (!resultPdfUrl) return;
        const link = document.createElement('a');
        link.href = resultPdfUrl;
        link.download = `reordered_${file.name}`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="pdf-reorder-container py-4">
            <style>{`
                .pdf-reorder-container {
                    max-width: 1000px;
                    margin: 0 auto;
                }
                .main-card {
                    background: #ffffff;
                    border: 1px solid #e1e8ed;
                    border-radius: 24px;
                    padding: 2.5rem;
                    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05);
                    margin-bottom: 2rem;
                }
                .upload-zone {
                    border: 2px dashed #cbd5e0;
                    border-radius: 16px;
                    padding: 3rem 2rem;
                    text-align: center;
                    transition: all 0.3s ease;
                    background: #f8fafc;
                    cursor: pointer;
                    margin-bottom: 2rem;
                    position: relative;
                }
                .upload-zone:hover {
                    border-color: #667eea;
                    background: #f0f4ff;
                }
                .upload-zone input {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    opacity: 0;
                    cursor: pointer;
                }
                .pages-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
                    gap: 20px;
                    margin-bottom: 2rem;
                }
                .page-card {
                    background: white;
                    border: 2px solid #edf2f7;
                    border-radius: 16px;
                    padding: 12px;
                    transition: all 0.2s;
                    position: relative;
                }
                .page-card:hover {
                    border-color: #667eea;
                    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.15);
                }
                .page-thumb {
                    width: 100%;
                    height: 180px;
                    object-fit: contain;
                    background: #f7fafc;
                    border-radius: 8px;
                    margin-bottom: 12px;
                    border: 1px solid #f1f5f9;
                }
                .page-label {
                    font-size: 0.75rem;
                    font-weight: 800;
                    color: #4a5568;
                    margin-bottom: 10px;
                    display: block;
                    text-align: center;
                }
                .reorder-controls {
                    display: flex;
                    justify-content: center;
                    gap: 8px;
                }
                .control-btn {
                    flex: 1;
                    padding: 6px;
                    border-radius: 8px;
                    border: 1px solid #e2e8f0;
                    background: #f8fafc;
                    color: #4a5568;
                    transition: all 0.2s;
                    display: flex;
