                    flex-grow: 1;
                    position: relative;
                }
                .pdf-canvas-container {
                    position: relative;
                    box-shadow: 0 0 60px rgba(0,0,0,0.8);
                    background: white;
                    cursor: crosshair;
                }
                .redaction-box {
                    position: absolute;
                    background: black;
                    border: 1px solid #334155;
                    pointer-events: all;
