                    padding: 1.5rem;
                    margin-bottom: 2rem;
                    border: 1px solid #edf2f7;
                }
                .gallery-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
                    gap: 20px;
                    margin-top: 2rem;
                }
                .page-card {
                    background: white;
