                        {isProcessing ? `Extracting... ${progress}%` : 'Extract All Pages as JPG'}
                    </Button>
                ) : (
                    <div className="d-flex gap-3 fade-in">
                        <Button 
                            variant="outline-warning" 
                            className="flex-grow-1"
