import React, { useState, useEffect } from 'react';
import { Form, Row, Col, Button, Toast, ToastContainer, InputGroup } from 'react-bootstrap';
import { 
    FaCopy, FaDownload, FaSyncAlt, FaParagraph, FaFont, 
    FaListUl, FaCheck, FaTrash, FaPenNib
} from 'react-icons/fa';

const LOREM_WORDS = [
    "lorem", "ipsum", "dolor", "sit", "amet", "consectetur", "adipiscing", "elit", "sed", "do", "eiusmod", "tempor", "incididunt", "ut", "labore", "et", "dolore", "magna", "aliqua", "ut", "enim", "ad", "minim", "veniam", "quis", "nostrud", "exercitation", "ullamco", "laboris", "nisi", "ut", "aliquip", "ex", "ea", "commodo", "consequat", "duis", "aute", "irure", "dolor", "in", "reprehenderit", "in", "voluptate", "velit", "esse", "cillum", "dolore", "eu", "fugiat", "nulla", "pariatur", "excepteur", "sint", "occaecat", "cupidatat", "non", "proident", "sunt", "in", "culpa", "qui", "officia", "deserunt", "mollit", "anim", "id", "est", "laborum"
];

const LoremIpsumGenerator = () => {
    const [result, setResult] = useState('');
    const [type, setType] = useState('paragraphs');
    const [count, setCount] = useState(3);
    const [startWithLorem, setStartWithLorem] = useState(true);
    const [showToast, setShowToast] = useState(false);
    const [toastMsg, setToastMsg] = useState('');

    const getRandomWord = () => LOREM_WORDS[Math.floor(Math.random() * LOREM_WORDS.length)];

    const generateSentence = () => {
        const length = Math.floor(Math.random() * 10) + 8;
        let sentence = [];
        for (let i = 0; i < length; i++) sentence.push(getRandomWord());
        let str = sentence.join(' ');
        return str.charAt(0).toUpperCase() + str.slice(1) + '.';
    };

    const generateParagraph = () => {
        const length = Math.floor(Math.random() * 4) + 4;
        let p = [];
        for (let i = 0; i < length; i++) p.push(generateSentence());
        return p.join(' ');
    };

    const handleGenerate = () => {
        let output = [];
        if (type === 'paragraphs') {
            for (let i = 0; i < count; i++) output.push(generateParagraph());
            let final = output.join('\n\n');
            if (startWithLorem) final = "Lorem ipsum dolor sit amet, " + final.charAt(0).toLowerCase() + final.slice(1);
            setResult(final);
        } else if (type === 'sentences') {
            for (let i = 0; i < count; i++) output.push(generateSentence());
            let final = output.join(' ');
            if (startWithLorem) final = "Lorem ipsum dolor sit amet. " + final;
            setResult(final);
        } else if (type === 'words') {
            for (let i = 0; i < count; i++) output.push(getRandomWord());
            let final = output.join(' ');
            if (startWithLorem) final = "Lorem ipsum " + final;
            setResult(final);
        } else if (type === 'lists') {
            for (let i = 0; i < count; i++) output.push("• " + generateSentence());
            setResult(output.join('\n'));
        }
    };

    useEffect(() => {
        handleGenerate();
    }, []);

    const handleCopy = () => {
        if (!result) return;
        navigator.clipboard.writeText(result);
        setToastMsg('Copied to clipboard!');
        setShowToast(true);
    };

    const handleDownload = () => {
        if (!result) return;
        const element = document.createElement("a");
        const file = new Blob([result], {type: 'text/plain'});
        element.href = URL.createObjectURL(file);
        element.download = "lorem-ipsum.txt";
        document.body.appendChild(element);
        element.click();
        setToastMsg('File downloaded!');
        setShowToast(true);
    };

    const handleClear = () => {
        setResult('');
        setToastMsg('Text cleared!');
        setShowToast(true);
    };

    return (
        <div className="lorem-generator-tool">
            <div className="control-panel p-4 glass-card rounded-4 mb-4 border">
                <Row className="g-3 align-items-end">
                    <Col md={3}>
                        <Form.Group>
                            <Form.Label className="fw-bold small text-muted">Generate Type</Form.Label>
                            <Form.Select 
                                value={type} 
                                onChange={(e) => setType(e.target.value)}
                                className="rounded-pill border-primary border-opacity-25"
                            >
                                <option value="paragraphs">Paragraphs</option>
                                <option value="sentences">Sentences</option>
                                <option value="words">Words</option>
                                <option value="lists">List Items</option>
                            </Form.Select>
                        </Form.Group>
                    </Col>
                    <Col md={3}>
                        <Form.Group>
                            <Form.Label className="fw-bold small text-muted">Quantity</Form.Label>
                            <InputGroup>
                                <Form.Control 
                                    type="number" 
                                    min="1" 
                                    max="50" 
                                    value={count} 
                                    onChange={(e) => setCount(parseInt(e.target.value) || 1)}
                                    className="rounded-start-pill border-primary border-opacity-25"
                                />
                                <InputGroup.Text className="rounded-end-pill bg-light border-primary border-opacity-25">
                                    {type}
                                </InputGroup.Text>
                            </InputGroup>
                        </Form.Group>
                    </Col>
                    <Col md={3}>
                        <Form.Check 
                            type="switch"
                            id="start-with-lorem"
                            label="Start with 'Lorem Ipsum'"
                            checked={startWithLorem}
                            onChange={(e) => setStartWithLorem(e.target.checked)}
                            className="mb-2 fw-medium"
                        />
                    </Col>
                    <Col md={3}>
                        <Button variant="primary" className="w-100 rounded-pill py-2 fw-bold" onClick={handleGenerate}>
                            <FaSyncAlt className="me-2" /> Generate
                        </Button>
                    </Col>
                </Row>
            </div>

            <Form.Group className="mb-4">
                <div className="d-flex justify-content-between align-items-center mb-2">
                    <Form.Label className="fw-bold mb-0">Generated Placeholder Text:</Form.Label>
                    <Button variant="link" className="text-danger p-0 text-decoration-none small" onClick={handleClear}>
                        <FaTrash className="me-1" /> Clear
                    </Button>
                </div>
                <Form.Control 
                    as="textarea" 
                    rows={12} 
                    value={result}
                    readOnly
                    placeholder="Click generate to see text here..."
                    className="border-0 bg-light p-4 rounded-4 shadow-sm"
                    style={{ fontSize: '1.05rem', lineHeight: '1.7', minHeight: '400px' }}
                />
            </Form.Group>

            <Row className="g-3 mb-4">
                <Col md={4}>
                    <div className="stats-card p-3 glass-card rounded-3 text-center border">
                        <FaParagraph className="text-primary mb-2" />
                        <h5 className="fw-bold mb-0">{result.split(/\n\n/).filter(x => x).length}</h5>
                        <span className="text-muted small">Paragraphs</span>
                    </div>
                </Col>
                <Col md={4}>
                    <div className="stats-card p-3 glass-card rounded-3 text-center border">
                        <FaPenNib className="text-success mb-2" />
                        <h5 className="fw-bold mb-0">{result.split(' ').filter(x => x).length}</h5>
                        <span className="text-muted small">Words</span>
                    </div>
                </Col>
                <Col md={4}>
                    <div className="stats-card p-3 glass-card rounded-3 text-center border">
                        <FaFont className="text-secondary mb-2" />
                        <h5 className="fw-bold mb-0">{result.length}</h5>
                        <span className="text-muted small">Characters</span>
                    </div>
                </Col>
            </Row>

            <div className="d-flex gap-3 justify-content-center">
                <Button variant="primary" className="rounded-pill px-5 py-2 fw-bold d-flex align-items-center shadow-sm" onClick={handleCopy}>
                    <FaCopy className="me-2" /> Copy to Clipboard
                </Button>
                <Button variant="success" className="rounded-pill px-5 py-2 fw-bold d-flex align-items-center shadow-sm" onClick={handleDownload}>
                    <FaDownload className="me-2" /> Download .txt
                </Button>
            </div>

            <div className="mt-5 pt-4 border-top">
                <h3 className="h5 fw-bold mb-3">About Lorem Ipsum Generator</h3>
                <p className="text-muted">
                    Lorem Ipsum is the industry standard dummy text used by designers and developers to simulate content in layouts. 
                    Our premium generator allows you to create precisely the amount of text you need, whether it's a few paragraphs for a blog post mock-up, 
                    a list of items for a sidebar, or just a few specific words for a headline.
                </p>
                <div className="row mt-3 text-muted small">
                    <div className="col-md-6">
                        <ul className="list-unstyled">
                            <li className="mb-2"><FaCheck className="text-success me-2" /> <strong>Professional Quality:</strong> Mimics natural sentence flow and paragraph length.</li>
                            <li><FaCheck className="text-success me-2" /> <strong>Clean Output:</strong> No hidden characters, just pure UTF-8 text.</li>
                        </ul>
                    </div>
                    <div className="col-md-6">
                        <ul className="list-unstyled">
                            <li className="mb-2"><FaCheck className="text-success me-2" /> <strong>Versatile:</strong> Generate paragraphs, sentences, words, or lists.</li>
                            <li><FaCheck className="text-success me-2" /> <strong>Fast:</strong> Instant generation with zero latency.</li>
                        </ul>
                    </div>
                </div>
            </div>

            <ToastContainer position="bottom-end" className="p-3">
                <Toast show={showToast} onClose={() => setShowToast(false)} delay={3000} autohide className="bg-dark text-white">
                    <Toast.Body className="d-flex align-items-center">
                        <FaCheck className="text-success me-2" /> {toastMsg}
                    </Toast.Body>
                </Toast>
            </ToastContainer>
        </div>
    );
};

export default LoremIpsumGenerator;

import React, { useState, useMemo } from 'react';
import { Form, Row, Col, Button, ButtonGroup, Toast, ToastContainer } from 'react-bootstrap';
import { 
    FaBold, FaItalic, FaHeading, FaQuoteLeft, FaLink, 
    FaCode, FaListUl, FaEye, FaEdit, FaDownload, 
    FaCopy, FaTrash, FaCheck 
} from 'react-icons/fa';

const MarkdownEditor = () => {
    const [markdown, setMarkdown] = useState('# Hello Markdown\n\nType your content here and see the magic on the right!');
    const [showToast, setShowToast] = useState(false);
    const [toastMsg, setToastMsg] = useState('');

    const parseMarkdown = (md) => {
        let html = md
            .replace(/^# (.*$)/gim, '<h1>$1</h1>')
            .replace(/^## (.*$)/gim, '<h2>$1</h2>')
            .replace(/^### (.*$)/gim, '<h3>$1</h3>')
            .replace(/^\> (.*$)/gim, '<blockquote class="border-start border-4 ps-3 text-muted">$1</blockquote>')
            .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
            .replace(/\*(.*)\*/gim, '<em>$1</em>')
            .replace(/`(.*?)`/gim, '<code class="bg-light p-1 rounded">$1</code>')
            .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' target='_blank'>$1</a>")
            .replace(/^\* (.*$)/gim, '<ul><li>$1</li></ul>')
            .replace(/<\/ul>\n<ul>/gim, '')
            .replace(/\n$/gim, '<br />')
            .replace(/\n/gim, '<br />');
        return html;
    };

    const previewHtml = useMemo(() => parseMarkdown(markdown), [markdown]);

    const insertText = (before, after = '') => {
        const textarea = document.getElementById('md-textarea');
        if (!textarea) return;
        const start = textarea.selectionStart;
        const end = textarea.selectionEnd;
        const selectedText = markdown.substring(start, end);
        const newText = markdown.substring(0, start) + before + selectedText + after + markdown.substring(end);
        setMarkdown(newText);
        textarea.focus();
    };

    const handleCopy = (content, type) => {
        navigator.clipboard.writeText(content);
        setToastMsg(`Copied ${type} to clipboard!`);
        setShowToast(true);
    };

    const handleDownload = () => {
        const element = document.createElement("a");
        const file = new Blob([markdown], {type: 'text/plain'});
        element.href = URL.createObjectURL(file);
        element.download = "document.md";
        document.body.appendChild(element);
        element.click();
        setToastMsg('File downloaded!');
        setShowToast(true);
    };

    return (
        <div className="markdown-editor-tool">
            <div className="toolbar p-2 glass-card rounded-4 mb-3 border d-flex flex-wrap gap-2">
                <ButtonGroup size="sm">
                    <Button variant="light" onClick={() => insertText('# ')} title="Heading 1"><FaHeading size={12} />1</Button>
                    <Button variant="light" onClick={() => insertText('## ')} title="Heading 2"><FaHeading size={12} />2</Button>
                </ButtonGroup>
                <ButtonGroup size="sm">
                    <Button variant="light" onClick={() => insertText('**', '**')} title="Bold"><FaBold /></Button>
                    <Button variant="light" onClick={() => insertText('*', '*')} title="Italic"><FaItalic /></Button>
                </ButtonGroup>
                <ButtonGroup size="sm">
                    <Button variant="light" onClick={() => insertText('> ')} title="Quote"><FaQuoteLeft /></Button>
                    <Button variant="light" onClick={() => insertText('[Link Text](https://example.com)')} title="Link"><FaLink /></Button>
                    <Button variant="light" onClick={() => insertText('`', '`')} title="Code"><FaCode /></Button>
                    <Button variant="light" onClick={() => insertText('* ')} title="Unordered List"><FaListUl /></Button>
                </ButtonGroup>
                <div className="ms-auto d-flex gap-2">
                    <Button variant="outline-danger" size="sm" onClick={() => setMarkdown('')}><FaTrash /> Clear</Button>
                </div>
            </div>

            <Row className="g-4">
                <Col lg={6}>
                    <div className="editor-container h-100">
                        <div className="d-flex justify-content-between align-items-center mb-2 px-2">
                            <span className="small fw-bold text-muted uppercase"><FaEdit className="me-1" /> Markdown Editor</span>
                            <span className="small text-muted">{markdown.length} Characters</span>
                        </div>
                        <Form.Control 
                            id="md-textarea"
                            as="textarea" 
                            value={markdown}
                            onChange={(e) => setMarkdown(e.target.value)}
                            className="border shadow-sm rounded-4 p-4 font-monospace"
                            style={{ height: '500px', fontSize: '0.95rem', resize: 'none' }}
                        />
                    </div>
                </Col>
                <Col lg={6}>
                    <div className="preview-container h-100 d-flex flex-column">
                        <div className="d-flex justify-content-between align-items-center mb-2 px-2">
                            <span className="small fw-bold text-muted uppercase"><FaEye className="me-1" /> Real-time Preview</span>
                            <div className="d-flex gap-2">
                                <Button variant="link" className="text-primary p-0 small text-decoration-none" onClick={() => handleCopy(markdown, 'Markdown')}>Copy MD</Button>
                                <Button variant="link" className="text-success p-0 small text-decoration-none" onClick={() => handleCopy(previewHtml, 'HTML')}>Copy HTML</Button>
                            </div>
                        </div>
                        <div 
                            className="preview-area border rounded-4 p-4 bg-white shadow-sm overflow-auto"
                            style={{ height: '500px' }}
                            dangerouslySetInnerHTML={{ __html: previewHtml }}
                        />
                    </div>
                </Col>
            </Row>

            <div className="d-flex gap-3 justify-content-center mt-4">
                <Button variant="primary" className="rounded-pill px-5 py-2 fw-bold d-flex align-items-center" onClick={handleDownload}>
                    <FaDownload className="me-2" /> Download Markdown (.md)
                </Button>
            </div>

            <div className="mt-5 pt-4 border-top">
                <h3 className="h5 fw-bold mb-3">About the Markdown Editor</h3>
                <p className="text-muted">
                    Markdown is a lightweight markup language with plain-text-formatting syntax. It is widely used by developers, content creators, and technical writers 
                    to format documents, readmes, and blog posts. Our premium editor provides a live side-by-side preview, making it easy to see your formatting changes instantly.
                </p>
                <div className="row g-4 mt-2">
                    <div className="col-md-4">
                        <div className="p-3 bg-light rounded-3 h-100">
                            <h6 className="fw-bold"><FaCheck className="text-success me-2" /> Lightweight</h6>
                            <p className="small text-muted mb-0">No external libraries required. Fast, secure, and client-side processing.</p>
                        </div>
                    </div>
                    <div className="col-md-4">
                        <div className="p-3 bg-light rounded-3 h-100">
                            <h6 className="fw-bold"><FaCheck className="text-success me-2" /> Formatting Tools</h6>
                            <p className="small text-muted mb-0">Includes a full toolbar for common styles like bold, italic, and lists.</p>
                        </div>
                    </div>
                    <div className="col-md-4">
                        <div className="p-3 bg-light rounded-3 h-100">
                            <h6 className="fw-bold"><FaCheck className="text-success me-2" /> Export Options</h6>
                            <p className="small text-muted mb-0">Copy your formatted HTML or download the raw Markdown file.</p>
                        </div>
                    </div>
                </div>
            </div>

            <ToastContainer position="bottom-end" className="p-3">
                <Toast show={showToast} onClose={() => setShowToast(false)} delay={3000} autohide className="bg-dark text-white">
                    <Toast.Body className="d-flex align-items-center">
                        <FaCheck className="text-success me-2" /> {toastMsg}
                    </Toast.Body>
                </Toast>
            </ToastContainer>

            <style>{`
                .preview-area h1 { font-size: 2rem; font-weight: 700; margin-bottom: 1rem; color: #0f172a; }
                .preview-area h2 { font-size: 1.5rem; font-weight: 600; margin-top: 1.5rem; margin-bottom: 0.75rem; color: #1e293b; }
                .preview-area h3 { font-size: 1.25rem; font-weight: 600; margin-top: 1.25rem; margin-bottom: 0.5rem; }
                .preview-area p { margin-bottom: 1rem; line-height: 1.6; color: #334155; }
                .preview-area blockquote { border-left: 4px solid #e2e8f0; padding-left: 1rem; font-style: italic; color: #64748b; margin: 1.5rem 0; }
                .preview-area ul { margin-bottom: 1rem; padding-left: 1.5rem; }
                .preview-area a { color: #2563eb; text-decoration: none; }
                .preview-area a:hover { text-decoration: underline; }
            `}</style>
        </div>
    );
};

export default MarkdownEditor;
